UPDATE users
username = #{username}, password = #{password}, realname = #{realname}, gender = #{gender}, age = #{age}, phone = #{phone}, email = #{email}, city = #{city}, nickname = #{nickname}, avatar_url = #{avatarUrl}, role = #{role}, status = #{status}, company_id = #{companyId}, company_name = #{companyName}, updated_at = NOW()
WHERE id = #{id}

mapper.select:
SELECT id, username, phone, avatar_url AS avatarUrl, realname, nickname, city, role, status, gender, age, DATE_FORMAT(created_at, '%Y-%m-%d %H:%i:%s') AS createdAt FROM users WHERE 1 = 1
AND (username LIKE CONCAT('%', #{keyword}, '%') OR phone LIKE CONCAT('%', #{keyword}, '%'))
AND username LIKE CONCAT('%', #{username}, '%')
AND role = #{role}
AND status = #{status}
ORDER BY role DESC, created_at DESC

SELECT u.id, u.username, u.phone, u.avatar_url AS avatarUrl, u.realname, u.nickname, u.city, u.gender, u.age, COALESCE(c.name, '') AS companyName, u.status, CASE WHEN u.company_id IS NULL OR u.company_id = 0 THEN 0 ELSE COALESCE(c.audit_status, 0) END AS auditStatus, DATE_FORMAT(u.created_at, '%Y-%m-%d %H:%i:%s') AS createdAt FROM users u LEFT JOIN companies c ON u.company_id = c.id WHERE u.role = 1
AND (u.realname LIKE CONCAT('%', #{name}, '%') OR u.nickname LIKE CONCAT('%', #{name}, '%'))
AND u.status = #{status}
HAVING auditStatus = #{auditStatus}
ORDER BY u.created_at DESC
